import React, { useState } from 'react';
import { FlatList } from 'react-native';

const App = () => {
  const [data, setData] = useState([
    { id: 1, name: 'Item 1' },
    { id: 2, name: 'Item 2' },
    { id: 3, name: 'Item 3' },
  ]);

  const updateItem = () => {
    const updatedData = [...data];
    updatedData[0].name = 'Updated Item 1';
    setData(updatedData);
  };

  return (
    <FlatList
      data={data}
      renderItem={({ item }) => <Text>{item.name}</Text>}
      keyExtractor={(item) => item.id.toString()}
      extraData={data} // notify the list when the data changes
    />
  );
};
```

